  "inlineSchema": "// ============================================================\n// SNAPALARM — Prisma Schema\n// Run: npx prisma migrate dev --name init\n// ============================================================\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ---- Enums ------------------------------------------------\n\nenum SubscriptionTier {\n  FREE\n  BASIC\n  PRO\n}\n\nenum SubStatus {\n  ACTIVE\n  CANCELLED\n  PAST_DUE\n  TRIALING\n}\n\nenum AlarmMode {\n  IMAGE_ONLY\n  IMAGE_WITH_AUDIO\n}\n\nenum GenerationStatus {\n  PENDING\n  QUEUED_FOR_BATCH\n  BATCH_SUBMITTED\n  GENERATING\n  COMPLETED\n  FAILED\n  FALLBACK\n  CANCELLED\n}\n\nenum ModerationStatus {\n  PENDING\n  APPROVED\n  REJECTED\n  UNDER_REVIEW\n}\n\n// ---- Users & Auth -----------------------------------------\n\nmodel User {\n  id              String   @id @default(cuid())\n  email           String   @unique\n  passwordHash    String?\n  oauthProvider   String?\n  oauthId         String?\n  language        String   @default(\"en\")\n  timezone        String   @default(\"UTC\")\n  snapAlarmFolder Boolean  @default(false)\n  createdAt       DateTime @default(now())\n  updatedAt       DateTime @updatedAt\n  credits         Int      @default(5)\n\n  alarms          Alarm[]\n  subscription    Subscription?\n  communityPosts  CommunityPost[]\n  votes           Vote[]\n  reports         Report[]\n  monthlyRankings MonthlyRanking[]\n  refreshTokens   RefreshToken[]\n\n  @@index([email])\n}\n\nmodel RefreshToken {\n  id        String   @id @default(cuid())\n  userId    String\n  user      User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  token     String   @unique\n  expiresAt DateTime\n  createdAt DateTime @default(now())\n\n  @@index([userId])\n  @@index([token])\n}\n\n// ---- Subscriptions & Credits ------------------------------\n\nmodel Subscription {\n  id                 String           @id @default(cuid())\n  userId             String           @unique\n  user               User             @relation(fields: [userId], references: [id])\n  tier               SubscriptionTier\n  status             SubStatus\n  revenuecatId       String?\n  stripeCustomerId   String?\n  currentPeriodStart DateTime\n  currentPeriodEnd   DateTime\n  cancelAtPeriodEnd  Boolean          @default(false)\n  createdAt          DateTime         @default(now())\n  updatedAt          DateTime         @updatedAt\n}\n\n// ---- Alarms — core entity ---------------------------------\n\nmodel Alarm {\n  id                    String           @id @default(cuid())\n  userId                String\n  user                  User             @relation(fields: [userId], references: [id])\n  title                 String\n  reason                String\n  humorLevel            Int // 1-4\n  fireTimeUtc           DateTime\n  timezoneSource        String\n  mode                  AlarmMode\n  originalImageS3Key    String\n  generatedImageS3Key   String?\n  generatedImageUrl     String?\n  generatedAudioS3Key   String?\n  generatedAudioUrl     String?\n  generatedText         String?\n  generationStatus      GenerationStatus @default(PENDING)\n  batchJobId            String?\n  batchWindow           String? // e.g. \"BATCH_A_2024-01-15\"\n  generationStartedAt   DateTime?\n  generationCompletedAt DateTime?\n  imageReadyAt          DateTime? // must be <= fireTimeUtc - 5min\n  retryCount            Int              @default(0)\n  fallbackReason        String?\n  calendarEventId       String?\n  isActive              Boolean          @default(true)\n  createdAt             DateTime         @default(now())\n  updatedAt             DateTime         @updatedAt\n\n  communityPost CommunityPost?\n  generationLog AIGenerationLog?\n\n  @@index([userId])\n  @@index([fireTimeUtc])\n  @@index([generationStatus])\n  @@index([batchWindow])\n}\n\n// ---- Community Pool ---------------------------------------\n\nmodel CommunityPost {\n  id               String           @id @default(cuid())\n  alarmId          String           @unique\n  alarm            Alarm            @relation(fields: [alarmId], references: [id])\n  userId           String\n  user             User             @relation(fields: [userId], references: [id])\n  moderationStatus ModerationStatus @default(PENDING)\n  moderationReason String?\n  voteCount        Int              @default(0)\n  isVisible        Boolean          @default(false)\n  sharedAt         DateTime         @default(now())\n\n  votes   Vote[]\n  reports Report[]\n\n  @@index([moderationStatus])\n  @@index([isVisible])\n}\n\nmodel Vote {\n  id              String        @id @default(cuid())\n  userId          String\n  user            User          @relation(fields: [userId], references: [id])\n  communityPostId String\n  communityPost   CommunityPost @relation(fields: [communityPostId], references: [id])\n  createdAt       DateTime      @default(now())\n\n  @@unique([userId, communityPostId])\n}\n\nmodel Report {\n  id              String        @id @default(cuid())\n  userId          String\n  user            User          @relation(fields: [userId], references: [id])\n  communityPostId String\n  communityPost   CommunityPost @relation(fields: [communityPostId], references: [id])\n  reason          String\n  createdAt       DateTime      @default(now())\n}\n\n// ---- AI Generation Audit Log ------------------------------\n\nmodel AIGenerationLog {\n  id          String   @id @default(cuid())\n  alarmId     String   @unique\n  alarm       Alarm    @relation(fields: [alarmId], references: [id])\n  modelUsed   String\n  humorLevel  Int\n  tokensUsed  Int\n  costUsd     Float\n  durationMs  Int\n  retryCount  Int      @default(0)\n  batchOrSync String // \"batch\" | \"sync\"\n  createdAt   DateTime @default(now())\n}\n\n// ---- Monthly Rankings Snapshot ----------------------------\n\nmodel MonthlyRanking {\n  id             String   @id @default(cuid())\n  userId         String\n  user           User     @relation(fields: [userId], references: [id])\n  yearMonth      String // e.g. \"2024-01\"\n  rank           Int\n  totalVotes     Int\n  creditsAwarded Int\n  createdAt      DateTime @default(now())\n\n  @@unique([userId, yearMonth])\n  @@index([yearMonth])\n}\n",
  "inlineSchemaHash": "7b871b034c3b6e1a44c1770982068a6d4391a8d966a774ced275eaad6e393a2a",
